import{_ as a,o as r,c as i,ag as t}from"./chunks/framework.BZohXCq9.js";const g=JSON.parse('{"title":"Three IP Scenario Cards — Design Doc","description":"","frontmatter":{},"headers":[],"relativePath":"plans/2026-03-14-three-ip-scenario-cards-design.md","filePath":"plans/2026-03-14-three-ip-scenario-cards-design.md","lastUpdated":null}'),s={name:"plans/2026-03-14-three-ip-scenario-cards-design.md"};function l(n,e,o,c,h,d){return r(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="three-ip-scenario-cards-—-design-doc" tabindex="-1">Three IP Scenario Cards — Design Doc <a class="header-anchor" href="#three-ip-scenario-cards-—-design-doc" aria-label="Permalink to &quot;Three IP Scenario Cards — Design Doc&quot;">​</a></h1><p>Date: 2026-03-14</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Three premium scenario-level cards for IPs with existing scraped source material:</p><ul><li>Chainsaw Man (電鋸人)</li><li>Attack on Titan (進撃の巨人)</li><li>Hunter x Hunter (全職獵人)</li></ul><p>Each card: one per IP, high quality, story-immersive, arc-selection model.</p><h2 id="shared-architecture" tabindex="-1">Shared Architecture <a class="header-anchor" href="#shared-architecture" aria-label="Permalink to &quot;Shared Architecture&quot;">​</a></h2><h3 id="card-structure" tabindex="-1">Card Structure <a class="header-anchor" href="#card-structure" aria-label="Permalink to &quot;Card Structure&quot;">​</a></h3><ul><li><strong>Type</strong>: Scenario (single card per IP)</li><li><strong>First Message</strong>: Two-step selection <ol><li>Choose character (with avatar + brief intro)</li><li>Choose story arc (3-4 major arcs)</li></ol></li><li><strong>System Prompt</strong>: World context + selected character personality + arc setup</li><li><strong>Lorebook</strong>: Conditional entries per arc (<code>arc_id == &quot;xxx&quot;</code>)</li><li><strong>Variables</strong>: <code>arc_id</code>, <code>player_character</code>, <code>story_phase</code>, affinity per character, IP-specific mechanics</li><li><strong>Rules</strong>: Story progression triggers, phase transitions, relationship changes</li><li><strong>messageRenderer</strong>: Unique per card, IP-themed, with character avatars from downloaded images</li><li><strong>Language</strong>: All user-facing text in Chinese, Japanese proper nouns preserved</li></ul><h3 id="messagerenderer-requirements" tabindex="-1">messageRenderer Requirements <a class="header-anchor" href="#messagerenderer-requirements" aria-label="Permalink to &quot;messageRenderer Requirements&quot;">​</a></h3><ul><li>Parse message content: dialogue, action, narration (visually distinct)</li><li>Character avatars from downloaded MAL images</li><li>Status panel (arc progress, relationships, IP mechanics)</li><li>IP-specific color scheme and visual motifs</li><li>All UI labels in Chinese</li></ul><h2 id="card-1-chainsaw-man-—-「恶魔猎人的日常」" tabindex="-1">Card 1: Chainsaw Man — 「恶魔猎人的日常」 <a class="header-anchor" href="#card-1-chainsaw-man-—-「恶魔猎人的日常」" aria-label="Permalink to &quot;Card 1: Chainsaw Man — 「恶魔猎人的日常」&quot;">​</a></h2><h3 id="playable-characters" tabindex="-1">Playable Characters <a class="header-anchor" href="#playable-characters" aria-label="Permalink to &quot;Playable Characters&quot;">​</a></h3><ul><li>デンジ (Denji) — 492407.jpg</li><li>早川アキ (Aki Hayakawa) — 395003.jpg</li><li>パワー (Power) — 494969.jpg</li><li>ヒグマヤマコベニ (Kobeni) — 467961.jpg</li></ul><h3 id="story-arcs" tabindex="-1">Story Arcs <a class="header-anchor" href="#story-arcs" aria-label="Permalink to &quot;Story Arcs&quot;">​</a></h3><ol><li><strong>永恒恶魔篇</strong> — Trapped in infinite hotel, 3-day fight</li><li><strong>武士刀篇</strong> — Public Safety ambush, revenge arc</li><li><strong>蕾塞篇</strong> — Rain-soaked romance and assassination</li><li><strong>支配恶魔篇</strong> — Makima&#39;s true identity, final confrontation</li></ol><h3 id="ip-mechanics" tabindex="-1">IP Mechanics <a class="header-anchor" href="#ip-mechanics" aria-label="Permalink to &quot;IP Mechanics&quot;">​</a></h3><ul><li>恐惧值 (Fear Level): affects devil power strength</li><li>血量 (Blood): drink blood to regenerate</li><li>契约代价 (Contract Cost): track lifespan/body costs</li></ul><h3 id="messagerenderer-theme" tabindex="-1">messageRenderer Theme <a class="header-anchor" href="#messagerenderer-theme" aria-label="Permalink to &quot;messageRenderer Theme&quot;">​</a></h3><p>Dark punk aesthetic. Blood red + iron gray palette. Chainsaw-tooth borders, blood splatter decorations. Character dialogue boxes with avatars.</p><h3 id="key-characters-with-images" tabindex="-1">Key Characters (with images) <a class="header-anchor" href="#key-characters-with-images" aria-label="Permalink to &quot;Key Characters (with images)&quot;">​</a></h3><p>Denji, Makima, Aki, Power, Reze, Kobeni, Pochita, Himeno, Kishibe, Beam, Angel Devil, Samurai Sword</p><h2 id="card-2-attack-on-titan-—-「自由的代价」" tabindex="-1">Card 2: Attack on Titan — 「自由的代价」 <a class="header-anchor" href="#card-2-attack-on-titan-—-「自由的代价」" aria-label="Permalink to &quot;Card 2: Attack on Titan — 「自由的代价」&quot;">​</a></h2><h3 id="playable-characters-1" tabindex="-1">Playable Characters <a class="header-anchor" href="#playable-characters-1" aria-label="Permalink to &quot;Playable Characters&quot;">​</a></h3><ul><li>エレン (Eren Yeager) — 216895.jpg</li><li>ミカサ (Mikasa Ackerman) — 215563.jpg</li><li>リヴァイ (Levi) — 241413.jpg</li><li>アルミン (Armin Arlert) — 220267.jpg</li></ul><h3 id="story-arcs-1" tabindex="-1">Story Arcs <a class="header-anchor" href="#story-arcs-1" aria-label="Permalink to &quot;Story Arcs&quot;">​</a></h3><ol><li><strong>托洛斯特攻防战</strong> — First titan transformation, humanity&#39;s first victory</li><li><strong>女型巨人篇</strong> — 57th Expedition, Female Titan pursuit</li><li><strong>玛利亚之墙夺还战</strong> — Beast Titan, serum choice, basement truth</li><li><strong>马莱篇</strong> — Infiltration, declaration of war</li></ol><h3 id="ip-mechanics-1" tabindex="-1">IP Mechanics <a class="header-anchor" href="#ip-mechanics-1" aria-label="Permalink to &quot;IP Mechanics&quot;">​</a></h3><ul><li>立体机动装置 (ODM Gear): fuel + blade durability</li><li>巨人化次数 (Titan Shifts): limited per arc</li><li>兵团信任度 (Corps Trust): affects ally support</li></ul><h3 id="messagerenderer-theme-1" tabindex="-1">messageRenderer Theme <a class="header-anchor" href="#messagerenderer-theme-1" aria-label="Permalink to &quot;messageRenderer Theme&quot;">​</a></h3><p>Military briefing style. Dark green + earthy brown palette. Wings of Freedom crest. Wall texture backgrounds. Battle report format panels.</p><h3 id="key-characters-with-images-1" tabindex="-1">Key Characters (with images) <a class="header-anchor" href="#key-characters-with-images-1" aria-label="Permalink to &quot;Key Characters (with images)&quot;">​</a></h3><p>Eren, Mikasa, Armin, Levi, Erwin, Hange, Jean, Annie, Krista/Historia, Ymir, Bertolt, Connie, Sasha, Reiner, Petra, Grisha</p><h2 id="card-3-hunter-x-hunter-—-「猎人的觉悟」" tabindex="-1">Card 3: Hunter x Hunter — 「猎人的觉悟」 <a class="header-anchor" href="#card-3-hunter-x-hunter-—-「猎人的觉悟」" aria-label="Permalink to &quot;Card 3: Hunter x Hunter — 「猎人的觉悟」&quot;">​</a></h2><h3 id="playable-characters-2" tabindex="-1">Playable Characters <a class="header-anchor" href="#playable-characters-2" aria-label="Permalink to &quot;Playable Characters&quot;">​</a></h3><ul><li>ゴン (Gon Freecss) — 174517.jpg</li><li>キルア (Killua Zoldyck) — 327920.jpg</li><li>クラピカ (Kurapika) — 549312.jpg</li><li>レオリオ (Leorio) — 549311.jpg</li></ul><h3 id="story-arcs-2" tabindex="-1">Story Arcs <a class="header-anchor" href="#story-arcs-2" aria-label="Permalink to &quot;Story Arcs&quot;">​</a></h3><ol><li><strong>猎人考试篇</strong> — Deadly selection, first encounter with Hisoka</li><li><strong>约克新城篇</strong> — Phantom Troupe vs mafia auction, Kurapika&#39;s revenge</li><li><strong>贪婪之岛篇</strong> — Nen training, game world adventure</li><li><strong>嵌合蚁篇</strong> — Ant King and Komugi, humanity&#39;s malice</li></ol><h3 id="ip-mechanics-2" tabindex="-1">IP Mechanics <a class="header-anchor" href="#ip-mechanics-2" aria-label="Permalink to &quot;IP Mechanics&quot;">​</a></h3><ul><li>念能力等级 (Nen Level): 纏→絶→練→發 progression</li><li>战斗经验值 (Combat XP): unlocks techniques</li><li>猎人积分 (Hunter Points): story progression currency</li></ul><h3 id="messagerenderer-theme-2" tabindex="-1">messageRenderer Theme <a class="header-anchor" href="#messagerenderer-theme-2" aria-label="Permalink to &quot;messageRenderer Theme&quot;">​</a></h3><p>Adventure map style. Emerald green + gold palette. Hunter License card elements. Nen aura glow borders. Hexagonal ability radar chart.</p><h3 id="key-characters-with-images-2" tabindex="-1">Key Characters (with images) <a class="header-anchor" href="#key-characters-with-images-2" aria-label="Permalink to &quot;Key Characters (with images)&quot;">​</a></h3><p>Gon, Killua, Kurapika, Leorio, Hisoka, Meruem, Chrollo, Netero, Neferpitou, Kite, Illumi, Alluka, Komugi, Ging, Biscuit</p><h2 id="image-assets" tabindex="-1">Image Assets <a class="header-anchor" href="#image-assets" aria-label="Permalink to &quot;Image Assets&quot;">​</a></h2><p>All character images downloaded to <code>sources/{slug}/images/</code>:</p><ul><li>Chainsaw Man: 24 images (4 Main + 20 Supporting)</li><li>Attack on Titan: 23 images (3 Main + 20 Supporting)</li><li>Hunter x Hunter: 24 images (4 Main + 20 Supporting)</li></ul><h2 id="output" tabindex="-1">Output <a class="header-anchor" href="#output" aria-label="Permalink to &quot;Output&quot;">​</a></h2><p>Cards written to <code>output/</code> directory as WorldDefinition v13 JSON.</p>',49)])])}const m=a(s,[["render",l]]);export{g as __pageData,m as default};
